function findMinimumBags(weights, n, W):
    // Use weighted quickselect approach
    indices = [0, 1, ..., n-1]
    selected = []

    function weightedSelect(start, end, needed):
        if start > end:
            return

        pivot_idx = medianOfMedians(weights, indices, start, end)
        pivot_val = weights[indices[pivot_idx]]

        // Partition around pivot
        left_end = partition(weights, indices, start, end, pivot_idx)

        // Calculate sum of elements > pivot
        right_sum = 0
        for i from left_end + 1 to end:
            right_sum += weights[indices[i]]

        if right_sum >= needed:
            // Recurse only on right
            weightedSelect(left_end + 1, end, needed)
        else:
            // Take all from right
            for i from left_end + 1 to end:
                selected.append(indices[i])
            // Take pivot and recurse on left
            selected.append(indices[left_end])
            needed -= (right_sum + weights[indices[left_end]])
            if needed > 0:
                weightedSelect(start, left_end - 1, needed)

    weightedSelect(0, n-1, W)
    return selected
```

